CREATE DEFINER=`root`@`localhost` PROCEDURE `SeedAttendanceAprilFirstCutoff`()
BEGIN
    DECLARE current_emp INT DEFAULT 1;
    DECLARE loop_date DATE;
    DECLARE end_date DATE DEFAULT '2026-04-15';

    -- Loop through employee IDs 1 to 56
    WHILE current_emp <= 56 DO
        
        -- Filter for IDs 1 to 5 AND 11 to 56
        IF current_emp <= 5 OR current_emp >= 11 THEN
            
            -- Reset date to the start of the April 1st cutoff
            SET loop_date = '2026-04-01';
            
            -- Loop through the dates of the cutoff
            WHILE loop_date <= end_date DO
                
                -- Check if it is a weekday (Monday to Friday)
                -- AND skip the specific holidays (April 2, 3, and 9)
                IF DAYOFWEEK(loop_date) BETWEEN 2 AND 6 
                   AND loop_date NOT IN ('2026-04-02', '2026-04-03', '2026-04-09') THEN
                    
                    INSERT INTO attendance (
                        employee_id, date, time_in, time_out, 
                        total_hours, minutes_late, undertime_hours, overtime_hours
                    ) VALUES (
                        CAST(current_emp AS CHAR), loop_date, '08:00:00', '17:00:00', 
                        8, 0, 0, 0
                    );
                END IF;
                
                -- Move to the next day
                SET loop_date = DATE_ADD(loop_date, INTERVAL 1 DAY);
            END WHILE;
            
        END IF;
        
        -- Move to the next employee
        SET current_emp = current_emp + 1;
    END WHILE;
END ;;
DELIMITER ;
