/*!50003 DROP PROCEDURE IF EXISTS `SP_GenerateManualTeachingPayroll` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_general_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'NO_ZERO_IN_DATE,NO_ZERO_DATE,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `SP_GenerateManualTeachingPayroll`(
    IN p_emp_id BIGINT, IN p_start_date DATE, IN p_end_date DATE,
    IN p_lec DOUBLE, IN p_lab DOUBLE, IN p_rate DECIMAL(10,2),
    IN p_holiday DECIMAL(10,2), IN p_suspension DECIMAL(10,2), IN p_loans DECIMAL(10,2)
)
BEGIN
    DECLARE v_admin_pay DECIMAL(10,2) DEFAULT 0;
    DECLARE v_period_admin_pay DECIMAL(10,2) DEFAULT 0;
    DECLARE v_gross_teaching DECIMAL(10,2) DEFAULT 0;
    DECLARE v_gross_income DECIMAL(10,2) DEFAULT 0;
    DECLARE v_sss DECIMAL(10,2) DEFAULT 0;
    DECLARE v_philhealth DECIMAL(10,2) DEFAULT 0;
    DECLARE v_pagibig DECIMAL(10,2) DEFAULT 0;
    DECLARE v_net DECIMAL(10,2) DEFAULT 0;

    START TRANSACTION;

    SELECT COALESCE(admin_pay, 0) INTO v_admin_pay FROM employee WHERE employee_id = p_emp_id;
    SET v_period_admin_pay = v_admin_pay / 2;

    -- Applied 1 Unit = 3 Hours for Lab, and Lab Rate = 75% of regular rate
    SET v_gross_teaching = (p_lec * p_rate) + ((p_lab * 3.0) * (p_rate * 0.75)) + p_holiday - p_suspension;
    
    SET v_gross_income = v_period_admin_pay + v_gross_teaching;
    IF v_gross_income < 0 THEN SET v_gross_income = 0; END IF;

    IF v_gross_income > 0 THEN
        SET v_sss = LEAST(v_gross_income, 30000.00) * 0.05;
        SET v_philhealth = GREATEST(LEAST(v_gross_income, 100000.00), 10000.00) * 0.025;
        
        -- Respecting the 2nd cutoff rule for Pag-IBIG
        IF DAY(p_end_date) > 15 THEN SET v_pagibig = 200.00; END IF;
    END IF;

    SET v_net = v_gross_income - (v_sss + v_philhealth + v_pagibig) - p_loans;
    IF v_net < 0 THEN SET v_net = 0; END IF;

    DELETE FROM payroll WHERE employee_id = p_emp_id AND pay_period_start = p_start_date AND pay_period_end = p_end_date;
    
    INSERT INTO payroll (
        employee_id, pay_period_start, pay_period_end, basic_salary, honorarium,
        gross_income, sss_deduction, philhealth_deduction, pagibig_deduction, 
        govt_contributions, loan_deductions, net_pay, total_earnings
    ) VALUES (
        p_emp_id, p_start_date, p_end_date, v_period_admin_pay, v_gross_teaching,
        v_gross_income, v_sss, v_philhealth, v_pagibig, 
        (v_sss + v_philhealth + v_pagibig), p_loans, v_net, v_gross_income
    );

    COMMIT;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
