/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_general_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'NO_ZERO_IN_DATE,NO_ZERO_DATE,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `SP_ProcessBatchTeachingPayroll`(
    IN p_emp_id BIGINT, IN p_start DATE, IN p_end DATE, IN p_loans DECIMAL(10,2),
    IN p_late_mins INT, IN p_ut_mins INT, IN p_absent_days INT, IN p_teaching_pay_total DECIMAL(10,2)
)
BEGIN
    DECLARE v_monthly DECIMAL(10,2) DEFAULT 0;
    DECLARE v_hourly DECIMAL(10,2) DEFAULT 0;
    DECLARE v_daily DECIMAL(10,2) DEFAULT 0;
    DECLARE v_minute DECIMAL(10,5) DEFAULT 0;
    DECLARE v_status VARCHAR(50) DEFAULT '';
    
    DECLARE v_honorarium DECIMAL(10,2) DEFAULT 0; 
    DECLARE v_longevity DECIMAL(10,2) DEFAULT 0; 
    DECLARE v_cash_gift DECIMAL(10,2) DEFAULT 0;
    DECLARE v_incentive DECIMAL(10,2) DEFAULT 0;
    DECLARE v_allowance DECIMAL(10,2) DEFAULT 0;
    DECLARE v_relocation DECIMAL(10,2) DEFAULT 0;
    
    DECLARE v_period_basic DECIMAL(10,2) DEFAULT 0;
    DECLARE v_late_deduct DECIMAL(10,2) DEFAULT 0;
    DECLARE v_ut_deduct DECIMAL(10,2) DEFAULT 0;
    DECLARE v_absent_deduct DECIMAL(10,2) DEFAULT 0;
    
    DECLARE v_gross DECIMAL(10,2) DEFAULT 0;
    DECLARE v_total_earnings DECIMAL(10,2) DEFAULT 0;
    DECLARE v_net DECIMAL(10,2) DEFAULT 0;
    
    DECLARE v_is_part_time BOOLEAN DEFAULT FALSE;

    SELECT COALESCE(admin_pay, 0), COALESCE(hourly_rate, 0), COALESCE(employee_status, ''), 
           COALESCE(honorarium, 0), COALESCE(longevity, 0), COALESCE(cash_gift, 0), 
           COALESCE(incentive, 0), COALESCE(allowance, 0), COALESCE(relocation_pay, 0)
    INTO v_monthly, v_hourly, v_status, v_honorarium, v_longevity, v_cash_gift, v_incentive, v_allowance, v_relocation
    FROM employee WHERE employee_id = p_emp_id LIMIT 1;

    IF LOWER(v_status) LIKE '%part%' OR LOWER(v_status) LIKE '%flexi%' THEN SET v_is_part_time = TRUE; END IF;

    IF v_monthly > 0 THEN
        SET v_daily = (v_monthly * 12) / 313;
        SET v_hourly = v_daily / 8;
    ELSEIF v_hourly > 0 THEN
        SET v_daily = v_hourly * 8;
    END IF;
    
    SET v_minute = v_hourly / 60;

    IF DATEDIFF(p_end, p_start) + 1 <= 16 THEN SET v_period_basic = v_monthly / 2;
    ELSE SET v_period_basic = v_monthly; END IF;

    IF v_is_part_time THEN
        SET v_late_deduct = 0; SET v_ut_deduct = 0; SET v_absent_deduct = 0;
    ELSE
        SET v_late_deduct = v_minute * p_late_mins;
        SET v_ut_deduct = v_minute * p_ut_mins;
        SET v_absent_deduct = v_daily * p_absent_days;
    END IF;

    SET v_total_earnings = p_teaching_pay_total + v_period_basic + v_honorarium + v_longevity + v_cash_gift + v_incentive + v_allowance + v_relocation;
    SET v_gross = v_total_earnings - v_late_deduct - v_ut_deduct - v_absent_deduct;
    IF v_gross < 0 THEN SET v_gross = 0; END IF;

    SET v_net = v_gross - p_loans;
    IF v_net < 0 THEN SET v_net = 0; END IF;

    DELETE FROM payroll WHERE employee_id = p_emp_id AND pay_period_start = p_start AND pay_period_end = p_end;
    
    INSERT INTO payroll (
        employee_id, pay_period_start, pay_period_end, basic_salary, honorarium, longevity, 
        cash_gift, incentive, allowance, relocation_pay,
        late_deduction, undertime_deduction, absent_deduction, sss_deduction, philhealth_deduction, pagibig_deduction, govt_contributions,
        sss_employer_share, philhealth_employer_share, pagibig_employer_share, loan_deductions, total_earnings, gross_income, net_pay,
        late_minutes, undertime_minutes, total_absences, minute_rate, daily_rate
    ) VALUES (
        p_emp_id, p_start, p_end, v_period_basic, v_honorarium, v_longevity,
        v_cash_gift, v_incentive, v_allowance, v_relocation,
        v_late_deduct, v_ut_deduct, v_absent_deduct, 0, 0, 0, 0,
        0, 0, 0, p_loans, v_total_earnings, v_gross, v_net,
        p_late_mins, p_ut_mins, p_absent_days, v_minute, v_daily
    );

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `SP_ProcessRegularPayroll` */;
