CREATE DEFINER=`root`@`localhost` PROCEDURE `SP_ProcessRegularPayroll`(
    IN p_emp_id BIGINT,
    IN p_start DATE,
    IN p_end DATE,
    IN p_applied_sss_loan DECIMAL(10,2),
    IN p_applied_hdmf_loan DECIMAL(10,2),
    IN p_adjustment DECIMAL(10,2),
    IN p_honorarium DECIMAL(10,2),
    IN p_longevity DECIMAL(10,2),
    IN p_late_mins INT,
    IN p_ut_mins INT,
    IN p_absent_days INT,
    IN p_ot_hours DOUBLE,
    IN p_holiday_pay DECIMAL(10,2),
    IN p_leave_with_pay_days INT,
    IN p_leave_without_pay_days INT,
    IN p_teaching_pay_total DECIMAL(10,2),
    IN p_total_hours_worked DOUBLE
)
BEGIN
    DECLARE v_monthly DECIMAL(10,2) DEFAULT 0;
    DECLARE v_hourly DECIMAL(10,2) DEFAULT 0;
    DECLARE v_daily DECIMAL(10,2) DEFAULT 0;
    DECLARE v_minute DECIMAL(10,5) DEFAULT 0;
    DECLARE v_status VARCHAR(50) DEFAULT '';
    
    DECLARE v_cash_gift DECIMAL(10,2) DEFAULT 0;
    DECLARE v_incentive DECIMAL(10,2) DEFAULT 0;
    DECLARE v_allowance DECIMAL(10,2) DEFAULT 0;
    DECLARE v_relocation DECIMAL(10,2) DEFAULT 0;
    
    DECLARE v_period_basic DECIMAL(10,2) DEFAULT 0;
    DECLARE v_late_deduct DECIMAL(10,2) DEFAULT 0;
    DECLARE v_ut_deduct DECIMAL(10,2) DEFAULT 0;
    DECLARE v_absent_deduct DECIMAL(10,2) DEFAULT 0;
    DECLARE v_leave_without_pay DECIMAL(10,2) DEFAULT 0;
    DECLARE v_leave_pay DECIMAL(10,2) DEFAULT 0;
    DECLARE v_ot_pay DECIMAL(10,2) DEFAULT 0;
    
    DECLARE v_gross DECIMAL(10,2) DEFAULT 0;
    DECLARE v_total_loans DECIMAL(10,2) DEFAULT 0;
    DECLARE v_total_earnings DECIMAL(10,2) DEFAULT 0;
    DECLARE v_net DECIMAL(10,2) DEFAULT 0;
    
    DECLARE v_is_part_time BOOLEAN DEFAULT FALSE;

    SELECT COALESCE(admin_pay, 0), COALESCE(hourly_rate, 0), COALESCE(employee_status, ''), 
           COALESCE(cash_gift, 0), COALESCE(incentive, 0), COALESCE(allowance, 0), COALESCE(relocation_pay, 0)
    INTO v_monthly, v_hourly, v_status, v_cash_gift, v_incentive, v_allowance, v_relocation
    FROM employee WHERE employee_id = p_emp_id LIMIT 1;

    IF LOWER(v_status) LIKE '%part%' OR LOWER(v_status) LIKE '%flexi%' THEN
        SET v_is_part_time = TRUE;
    END IF;

    IF v_monthly > 0 THEN
        SET v_daily = (v_monthly * 12) / 313;
        SET v_hourly = v_daily / 8;
    ELSEIF v_hourly > 0 THEN
        SET v_daily = v_hourly * 8;
    END IF;
    SET v_minute = v_hourly / 60;

    IF DATEDIFF(p_end, p_start) + 1 <= 16 THEN
        SET v_period_basic = v_monthly / 2;
    ELSE
        SET v_period_basic = v_monthly;
    END IF;

    IF NOT v_is_part_time THEN
        SET v_late_deduct = v_minute * p_late_mins;
        SET v_ut_deduct = v_minute * p_ut_mins;
        SET v_absent_deduct = v_daily * p_absent_days;
        SET v_leave_without_pay = v_daily * p_leave_without_pay_days;
    END IF;

    SET v_leave_pay = v_daily * p_leave_with_pay_days;
    SET v_ot_pay = v_hourly * p_ot_hours * 1.25;

    SET v_total_earnings = v_period_basic + p_teaching_pay_total + p_adjustment + p_honorarium + p_longevity + v_ot_pay + p_holiday_pay + v_leave_pay + v_allowance + v_relocation + v_cash_gift + v_incentive;
    
    SET v_gross = v_total_earnings - v_late_deduct - v_ut_deduct - v_absent_deduct - v_leave_without_pay;
    IF v_gross < 0 THEN SET v_gross = 0; END IF;

    SET v_total_loans = p_applied_sss_loan + p_applied_hdmf_loan;
    SET v_net = v_gross - v_total_loans;
    IF v_net < 0 THEN SET v_net = 0; END IF;

    DELETE FROM payroll WHERE employee_id = p_emp_id AND pay_period_start = p_start AND pay_period_end = p_end;
    
    INSERT INTO payroll (
        employee_id, pay_period_start, pay_period_end, basic_salary, honorarium, longevity,
        cash_gift, incentive, allowance, relocation_pay,
        adjustment, overtime_pay, holiday_pay, leave_pay, leave_without_pay,
        late_deduction, undertime_deduction, absent_deduction, 
        sss_deduction, philhealth_deduction, pagibig_deduction, govt_contributions,
        sss_employer_share, philhealth_employer_share, pagibig_employer_share, 
        sss_loan, hdmf_loan, loan_deductions, total_earnings, gross_income, net_pay,
        late_minutes, undertime_minutes, total_absences, minute_rate, daily_rate
    ) VALUES (
        p_emp_id, p_start, p_end, v_period_basic, p_honorarium, p_longevity,
        v_cash_gift, v_incentive, v_allowance, v_relocation,
        p_adjustment, v_ot_pay, p_holiday_pay, v_leave_pay, v_leave_without_pay,
        v_late_deduct, v_ut_deduct, v_absent_deduct, 
        0, 0, 0, 0,
        0, 0, 0, 
        p_applied_sss_loan, p_applied_hdmf_loan, v_total_loans, v_total_earnings, v_gross, v_net,
        p_late_mins, p_ut_mins, p_absent_days, v_minute, v_daily
    );

END ;;
DELIMITER ;
