CREATE DEFINER=`root`@`localhost` PROCEDURE `SP_RecordTimeIn`(
    IN p_emp_id VARCHAR(50), 
    IN p_time_in TIME, 
    IN p_date DATE
)
BEGIN
    DECLARE v_minutes_late INT DEFAULT 0;
    DECLARE v_shift_start TIME DEFAULT '08:00:00';
    
    IF p_time_in > '08:15:00' THEN
        SET v_minutes_late = TIMESTAMPDIFF(MINUTE, v_shift_start, p_time_in);
    END IF;

    IF EXISTS (SELECT 1 FROM attendance WHERE employee_id = p_emp_id AND date = p_date) THEN
        UPDATE attendance 
        SET time_in = p_time_in, minutes_late = v_minutes_late 
        WHERE employee_id = p_emp_id AND date = p_date;
    ELSE
        INSERT INTO attendance (employee_id, date, time_in, minutes_late) 
        VALUES (p_emp_id, p_date, p_time_in, v_minutes_late);
    END IF;
END ;;
DELIMITER ;
