CREATE DEFINER=`root`@`localhost` PROCEDURE `SP_RecordTimeOut`(
    IN p_emp_id VARCHAR(50), 
    IN p_time_out TIME, 
    IN p_date DATE
)
BEGIN
    DECLARE v_time_in TIME;
    DECLARE v_elapsed_mins INT DEFAULT 0;
    DECLARE v_break_mins INT DEFAULT 0;
    DECLARE v_work_mins INT DEFAULT 0;
    DECLARE v_ot_mins INT DEFAULT 0;
    DECLARE v_ut_mins INT DEFAULT 0;
    DECLARE v_shift_end TIME DEFAULT '17:00:00';

    SELECT time_in INTO v_time_in FROM attendance WHERE employee_id = p_emp_id AND date = p_date LIMIT 1;

    IF v_time_in IS NOT NULL THEN
        SET v_elapsed_mins = TIMESTAMPDIFF(MINUTE, v_time_in, p_time_out);
        
        IF v_elapsed_mins > 300 THEN SET v_break_mins = 60; END IF;
        
        SET v_work_mins = GREATEST(0, v_elapsed_mins - v_break_mins);
        
        IF v_work_mins > 480 THEN SET v_ot_mins = v_work_mins - 480; END IF;
        
        IF p_time_out < v_shift_end THEN
            SET v_ut_mins = TIMESTAMPDIFF(MINUTE, p_time_out, v_shift_end);
        END IF;

        UPDATE attendance 
        SET time_out = p_time_out, 
            total_hours = v_work_mins, 
            overtime_hours = v_ot_mins, 
            undertime_hours = v_ut_mins
        WHERE employee_id = p_emp_id AND date = p_date;
    END IF;
END ;;
DELIMITER ;
